  ('promotion-d0d1b9a2-moex-00084', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報第4號規定，庚機關有機械設備1部，成本100萬元，已計提折舊60萬元， 經評估公允價值50萬元，於X2年1月26日向A公司換入汽車1輛，屬具商業實質之交換。庚 機關在有收取現金10萬元、未收取現金、支付現金10萬元等三種情況下，換入汽車應認列之成 本分別為何？', '["均為40萬元", "30萬元、40萬元、50萬元", "40萬元、50萬元、60萬元", "60萬元、50萬元、40萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
