  ('promotion-d0d1b9a2-moex-00086', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報第3號規定，有關政府支出認列之會計處理，下列敘述何者正確？', '["委辦支出，對先行撥付受託者備用款項，其未支用部分，會計期間終了應認列為暫付款項", "退休金支出，若採確定提撥退休金制，應於支付義務已發生且金額能可靠衡量時，認列為支出", "週期性支出，法令規定有支付時期者，應於支付義務已發生且金額能可靠衡量時，認列為支出", "不同政府間之補（協）助，資源提供者若未設定條件，應於承諾給付，且支付義務已發生及金 額能可靠衡量時，認列為支出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00087', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-112-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報第7號規定，國家公園遭遊客亂丟廢棄物，依法應由遊客負擔廢棄物清理費 用，民眾預期政府會先行清理，預估清理費用2萬元，政府對於該筆預估清理費用，應為之會計 處理為何？', '["無須處理", "揭露或有負債2萬元", "認列負債準備2萬元", "屬負債準備，但以揭露方式處理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "128bbba96ff7", "answer_pdf_sha1": "28d10d14a462", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
